What does this program print?

```cpp
#include <iostream>
constexpr int tri(int n) {
    int s = 0;
    for (int i = 1; i <= n; ++i) s += i;
    return s;
}
int main() {
    constexpr int a = tri(4);
    constexpr int b = tri(5);
    std::cout << a << " " << b << "\n";
}
```

